import { ipcMain, BrowserWindow } from 'electron';
import { IPC_CHANNELS, InstallNginxCertbotSchema, ApiResult } from './types';
import { provisioningService } from '../services/ProvisioningService';

export function registerProvisioningHandlers() {
  // Install nginx and certbot
  ipcMain.handle(IPC_CHANNELS.PROVISION_INSTALL_NGINX_CERTBOT, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { serverId } = InstallNginxCertbotSchema.parse(input);

      // Set up progress event forwarding to renderer
      const progressHandler = (event: any) => {
        const win = BrowserWindow.getAllWindows()[0];
        if (win) {
          win.webContents.send('progress:update', event);
        }
      };

      provisioningService.on('progress', progressHandler);

      try {
        await provisioningService.installNginxAndCertbot(serverId);
        return { success: true };
      } finally {
        provisioningService.off('progress', progressHandler);
      }
    } catch (error) {
      console.error('Error installing nginx and certbot:', error);
      return { success: false, error: String(error) };
    }
  });
}
